head.script:
scwin.vCheck = true;
scwin.hid_kcomcd = "DBEX";

scwin.onpageload = function() {
    scwin.hid_kcomcd = "DBEX";
};

scwin.onUdcCompleted = function() {
    $c.gus.cfDisableObjects([ed_cscd1, txt_csnm1, ed_cscd2, txt_csnm2]);
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.b_Cancel_onclick = function(e) {
    scwin.f_Cancel();
};

scwin.b_Save_onclick = function(e) {
    scwin.f_Save();
};

scwin.b_Delete_onclick = function(e) {
    scwin.f_Delete();
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([ed_blno]);
};

scwin.f_Retrieve = async function() {
    ds_partialList.removeAll();
    ds_hsnInfo.removeAll();
    if (ed_blno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["House B/L No"]);
        ed_blno.setFocus();
        return;
    }
    ds_Search.set("blno", ed_blno.getValue().trim());
    ds_Search.set("rfno", ds_Search.get("rfno").trim());
    ds_Search.set("kcomcd", scwin.hid_kcomcd);
    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_Cancel = function() {
    ds_partialList.undoAll();
    ds_hsnInfo.undoAll();
};

scwin.f_Save = async function() {
    if (await scwin.f_ReqFieldChk()) {
        if (ds_partialList.getCellData(0, "blno") == "") {
            ds_partialList.setCellData(0, "blno", ed_blno.getValue());
            if (ds_partialList.getCellData(0, "blno") == "") {
                await $c.win.alert("BL번호는 필수 입력항목입니다");
                ed_blno.setFocus();
                return false;
            }
        }

        for (let i = 0; i < ds_hsnInfo.getRowCount(); i++) {
            ds_hsnInfo.setCellData(i, "blno", ds_partialList.getCellData(0, "blno"));
        }

        if (ds_partialList.getCellData(0, "rfno") == "") {
            ds_partialList.setRowStatus(0, "C");
        }

        await $c.sbm.execute(sbm_Save);
        scwin.f_RfnoLoading();
    }
};

scwin.f_ReqFieldChk = async function() {
    let chk = await $c.gus.cfValidate([tb_headerMandantory]);
    if (!chk) {
        return false;
    }
    return true;
};

scwin.f_Delete = async function() {
    let chk = await $c.win.confirm(MSG_CM_CRM_004);
    if (chk) {
        ds_partialList.removeRow(0);
        for (let i = 0; i < ds_hsnInfo.getRowCount(); i++) {
            ds_hsnInfo.removeRow(i);
        }

        await $c.sbm.execute(sbm_Delete);
        scwin.f_RfnoLoading();
    }
};

scwin.f_RfnoLoading = async function() {
    let param1 = "";
    let param2 = "";
    param1 = ed_blno.getValue().trim();
    param2 = scwin.hid_kcomcd;

    if (param1.length > 0) {
        ds.set("sysCd", "ilCommonEBC");
        ds.set("queryId", "retriveAirImportCargoManifestPartialRfnoCombo");
        ds.set("param1", param1);
        ds.set("param2", param2);
        await $c.sbm.execute(sbm_RfnoLoading);
    } else {
        ds_Rfno.removeAll();
    }
};

scwin.f_ChkKeyCode = function(ds, row, colid) {
    try {
        let str = ds.getCellData(row, colid);
        let chkStr = "";
        let comStr = "";
        let badStr = "";
        for (let i = 0; i < str.length; i++) {
            chkStr = str.charCodeAt(i);
            if ((chkStr >= 33) && (chkStr <= 39)) {
                badStr += str.charAt(i);
            } else if ((chkStr >= 91) && (chkStr <= 96)) {
                badStr += str.charAt(i);
            } else if ((chkStr >= 123) && (chkStr <= 126)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 63)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 64)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 43)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 59)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 0)) {
                badStr += str.charAt(i);
            } else {
                comStr += str.charAt(i);
            }
        }
        ds.setCellData(row, colid, comStr);
    } catch (e) {
        scwin.vCheck = false;
    }
};

scwin.f_PopUp = function(disGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let rtnList;
    let pCode = "";
    let pName = "";
    switch (disGubun) {
        case "CustomInfo":
            udc_cscd1.ilCommonPopUp(scwin.callbackCustomInfo,
                ed_cscd1.getValue().trim(),
                txt_csnm1.getValue().trim(),
                pWinCloseTF,
                '2',
                '관할세관 Code, 관할세관 Name',
                '130,300',
                "3,4,5,6,7,8,9,10",
                null,
                '500',
                '500',
                null,
                null,
                null,
                pAllSearchTF,
                "관할세관 Search,관할세관 Code, 관할세관 Name",
                pNoDataCloseTF
            );
            break;

        case "CustomSectionInfo":
            udc_cscd2.ilCommonPopUp(scwin.callbackCustomSectionInfo,
                ed_cscd2.getValue().trim(),
                txt_csnm2.getValue().trim(),
                pWinCloseTF,
                '2',
                "세관과 Code, 세관과 Name",
                '130,300',
                "3,4,5,6,7,8,9,10",
                null,
                '500',
                '500',
                null,
                null,
                null,
                pAllSearchTF,
                "세관과 Search,세관과 Code, 세관과 Name",
                pNoDataCloseTF
            );
            break;

        case "PackageCode":
            let code = ds_hsnInfo.getCellData(ds_hsnInfo.getRowPosition(), "pkgUnit");
            udc_comCode_Grid.ilCommonPopUp(scwin.callbackPackageCode,
                code,
                '',
                pWinCloseTF,
                '2',
                "Package Code, Package Name",
                '130,300',
                "3,4,5,6,7,8,9,10",
                null,
                '500',
                '500',
                null,
                null,
                null,
                pAllSearchTF,
                "Package Code Search,Package Code, Package Name",
                pNoDataCloseTF
            );
            break;

        case "WeightUnitCode":
            udc_comCode_Grid.ilCommonPopUp(scwin.callbackWeightUnitCode,
                ed_wtUnit.getValue().trim(),
                '',
                pWinCloseTF,
                '2',
                "Weight Unit Code, Weight Unit Name",
                '130,300',
                "3,4,5,6,7,8,9,10",
                null,
                '500',
                '500',
                null,
                null,
                null,
                pAllSearchTF,
                "Weight Unit Search,Weight Unit Code, Weight Unit Name",
                pNoDataCloseTF
            );
            break;
    }
};

scwin.callbackCustomInfo = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_cscd1, txt_csnm1);
};

scwin.callbackCustomSectionInfo = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_cscd2, txt_csnm2);
};

scwin.callbackPackageCode = function(rtnList) {
    if (rtnList != null) {
        ds_hsnInfo.setCellData(ds_hsnInfo.getRowPosition(), "pkgUnit", rtnList[0]);
    }
};

scwin.callbackWeightUnitCode = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_wtUnit, '');
};

scwin.f_BeforePopUpEd = function(nmObj, cdObj, gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let cdObjVal = cdObj.getValue().trim();
    let isModified = (cdObj._previousValue !== undefined && cdObj._previousValue !== cdObj.getValue());
    if (isModified) {
        if (cdObjVal == "") {
            nmObj.setValue("");
        } else {
            nmObj.setValue("");
            scwin.f_PopUp(gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF);
        }
    }
};

scwin.f_ChkPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_PopUp(disGubun, 'T', 'F', 'F');
    } else {
        scwin.f_PopUp(disGubun, 'T', 'F', 'F');
    }
};

scwin.f_addRow = async function() {
    if (ds_partialList.getRowCount() == 0) {
        await $c.win.alert("분할/분할취소 정보를 먼저 등록해 주세요");
        return false;
    } else {
        if (ds_partialList.getCellData(0, "mrn") == "" || ds_partialList.getCellData(0, "msn") == ""
            || ds_partialList.getCellData(0, "hsn") == "") {
            await $c.win.alert("MRN / MSN / HSN 정보를 입력해 주세요");
            return false;
        }
        if (lc_mfGb.getValue() != "1" && lc_mfGb.getValue() != "2") {
            await $c.win.alert("신고유형을 선택해 주세요");
            lc_mfGb.setFocus();
            return false;
        }
    }

    ds_hsnInfo.insertRow();
    let row = ds_hsnInfo.getRowPosition();
    ds_hsnInfo.setCellData(row, "kcomcd", ds_partialList.getCellData(0, "kcomcd"));
    ds_hsnInfo.setCellData(row, "rfno", ds_partialList.getCellData(0, "rfno"));
    if (ds_partialList.getCellData(0, "rfno") == "") {
        ds_hsnInfo.setCellData(row, "rfno",
            ds_partialList.getCellData(0, "mrn")
            + ds_partialList.getCellData(0, "msn")
            + ds_partialList.getCellData(0, "hsn")
        );
    }
    ds_hsnInfo.setCellData(row, "blno", ds_partialList.getCellData(0, "blno"));
    ds_hsnInfo.setCellData(row, "mfGb", lc_mfGb.getValue());
    ds_hsnInfo.setCellData(row, "seq", row + 1);
};

scwin.f_deleteRow = function() {
    ds_hsnInfo.removeRow(ds_hsnInfo.getRowPosition());
};

scwin.btn_addRowIntnl2_onclick = function(e) {
    scwin.f_addRow();
};

scwin.btn_deleteRowIntnl2_onclick = function(e) {
    ds_hsnInfo.removeRow(ds_hsnInfo.getRowPosition());
};

scwin.btn_undoMarkIntnl2_onclick = function(e) {
    ds_hsnInfo.undoRow(ds_hsnInfo.getRowPosition());
};

scwin.sbm_retrieve_submitdone = async function(e) {
    if (ds_partialList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    } else {
        if (ds_partialList.getCellData(0, "flag") == "INSERT") {
            ds_partialList.setRowStatus(0, "C");
            $c.gus.cfEnableObjects([ed_mrn, ed_msn, ed_hsn]);
        } else {
            $c.gus.cfDisableObjects([ed_mrn, ed_msn, ed_hsn]);
        }
    }
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_Save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_Retrieve();
};

scwin.sbm_Save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_Delete_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_004);
    scwin.f_Retrieve();
};

scwin.sbm_Delete_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_RfnoLoading_submitdone = function(e) {
};

scwin.ds_partialList_oncelldatachange = function(info) {
    scwin.f_ChkKeyCode(ds_partialList, info.row, info.colId);
};

scwin.ed_blno_onblur = function(e) {
    scwin.f_RfnoLoading();
};

scwin.ed_cscd1_onblur = function(e) {
    scwin.f_BeforePopUpEd(txt_csnm1, ed_cscd1, 'CustomInfo', "T", "F", "F");
};

scwin.ed_cscd2_onblur = function(e) {
    scwin.f_BeforePopUpEd(txt_csnm2, ed_cscd2, "CustomSectionInfo", "T", "F", "F");
};

scwin.gr_hsnInfo_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    if (columnId == "pkgUnit") {
        scwin.f_PopUp("PackageCode", "T", "F", "F");
    }
};
